import React from 'react';
import ReactDOM from 'react-dom';

interface AdjustDecisionModalProps {
    isOpen: boolean;
    type: 'approve' | 'reject';
    onClose: () => void;
    onConfirm: () => void;
    adjustDirection: string;   // 'add' | 'deduct'
    adjustAmount: number;
    currentTotalPay: number;
}

export const AdjustDecisionModal: React.FC<AdjustDecisionModalProps> = ({
    isOpen, type, onClose, onConfirm,
    adjustDirection, adjustAmount, currentTotalPay,
}) => {
    const modalRoot = document.getElementById('modal-root');

    React.useEffect(() => {
        if (isOpen) {
            document.body.classList.add('modal-open');
        }
        return () => document.body.classList.remove('modal-open');
    }, [isOpen]);

    if (!isOpen || !modalRoot) return null;

    const isApprove = type === 'approve';
    const title = isApprove ? '조정 승인' : '조정 거절';
    const sign = adjustDirection === 'add' ? '+' : '-';
    const finalPay = adjustDirection === 'add'
        ? currentTotalPay + adjustAmount
        : currentTotalPay - adjustAmount;

    return ReactDOM.createPortal(
        <div className="modal" style={{ display: 'block', backgroundColor: 'rgba(0,0,0,0.5)' }} onClick={onClose}>
            <div className="modal-dialog" onClick={(e) => e.stopPropagation()}>
                <div className="modal-content" style={{ backgroundColor: 'white' }}>
                    <div className="modal-header line-header">
                        <h3>{title}</h3>
                    </div>

                    <div className="modal-body">
                        <div className="round-box mt10">
                            <div className="round-body">
                                <div className="info-row">
                                    <span className="label">추가 제안 금액</span>
                                    <span className="cont">
                                        <strong className="text-red">
                                            {sign}{adjustAmount.toLocaleString()} 원
                                        </strong>
                                    </span>
                                </div>
                                <div className="info-row">
                                    <span className="label">최종 급여 금액</span>
                                    <span className="cont">
                                        <strong>{finalPay.toLocaleString()} 원</strong>
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="modal-info-p mt20">
                            {isApprove ? (
                                <>
                                    <span className="block">승인 시 기존 결제가 취소되고</span>
                                    <span className="block">승인된 최종 급여 금액으로 결제됩니다.</span>
                                    <strong className="block mt10">코디의 돌봄 급여 금액 조정 신청을</strong>
                                    <strong className="block">승인하시겠습니까?</strong>
                                </>
                            ) : (
                                <>
                                    <strong className="block">코디의 돌봄 급여 금액 조정 신청을</strong>
                                    <strong className="block">거절하시겠습니까?</strong>
                                </>
                            )}
                        </div>
                    </div>

                    <div className="modal-footer">
                        <div className="modal_btn">
                            <button type="button" className="btn cancel" onClick={onClose}>취소</button>
                            <button type="button" className="btn confirm" onClick={onConfirm}>
                                {isApprove ? '승인' : '거절'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>,
        modalRoot
    );
};
